INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercero Básico', 'Educación Física', '1. Practica las capacidades condicionales pertinentes para un buen rendimiento físico.', ARRAY['1.1. Alcanza la resistencia de corta duración por medio de recorridos en tramos cortos, saltos de cuerda o subir el escalón sin dificultad.', '1.2. Aplica la fuerza resistencia en repetidas contracciones musculares y periodos de tiempo sin deformar la técnica del ejercicio.', '1.3. Mejora de forma eficaz su capacidad de rapidez de reacción como respuesta a diferentes estímulos en el menor tiempo posible.', '1.4. Desarrolla agilidad fácilmente cuando cambia en diferentes situaciones motrices.']),
('Tercero Básico', 'Educación Física', '2. Realiza prácticas deportivas promoviendo la responsabilidad y la comunicación en la comunidad.', ARRAY['2.1. Aplica la técnica correcta en las diferentes pruebas de pista y campo en atletismo.', '2.2. Resuelve correctamente situaciones técnicas defensivas y ofensivas del baloncesto.', '2.3. Combina correctamente situaciones técnicas y tácticas defensivas y ofensivas en el fútbol de forma individual.', '2.4. Resuelve correctamente situaciones técnicas defensivas y ofensivas del voleibol.', '2.5. Ejecuta correctamente acciones técnicas defensivas y ofensivas de forma individual y grupal en el balonmano.', '2.6. Realiza correctamente la construcción de composiciones gimnásticas, coordinando ritmos musicales y coreografía para la mejora de la expresión corporal.', '2.7. Ejecuta diferentes tipos de ataque y defensa en el ajedrez anotando de forma correcta los movimientos.', '2.8. Emplea coordinadamente habilidades motrices combinadas, para ejecutar acciones que favorezcan la aplicación de la técnica del chaaj o juego de pelota maya.']),
('Tercero Básico', 'Educación Física', '3. Organiza un plan de actividad física permanente para mejoramiento de la calidad de vida individual y familiar.', ARRAY['3.1. Propone alternativas de solución ante problemas que afectan la salud de las personas.', '3.2. Expone las etapas de un proyecto productivo, tomado en relación a la actividad física.', '3.3. Construye estrategias que le permitan alcanzar una vida saludable, valorando el trabajo cooperativo.']);
